section.code:
{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "type": "object",
  "title": "substack-beehiiv-pick-output",
  "required": [
    "recommendation",
    "rationale_criteria",
    "scores",
    "migration_cost_estimate_usd",
    "date",
    "signature",
    "forbidden_seen"
  ],
  "properties": {
    "recommendation": {
      "description": "Pick."
    },
    "rationale_criteria": {
      "description": "Cited criteria (\u22653)."
    },
    "scores": {
      "description": "Per-vendor score 1-5 across criteria."
    },
    "migration_cost_estimate_usd": {
      "description": "Switching cost."
    },
    "date": {
      "description": "Decision date."
    },
    "signature": {
      "description": "Owner."
    },
    "forbidden_seen": {
      "description": "Forbidden patterns matched (must be empty)."
    }
  }
}
